import os, re
pattern = re.compile(rb'FLAG\{[^\n\r]*\}')
dirs = ['/home', '/etc', '/var', '/usr', '/opt', '/srv', '/root']
skip = ['/proc', '/sys', '/dev', '/run', '/tmp', '/var/lib/mysql']
max_depth = 4
max_size = 200_000
for base in dirs:
    if not os.path.exists(base):
        continue
    base_depth = base.count(os.sep)
    for root, dirnames, filenames in os.walk(base):
        rel_depth = root.count(os.sep) - base_depth
        if rel_depth > max_depth:
            dirnames[:] = []
            continue
        if any(root.startswith(s) for s in skip):
            dirnames[:] = []
            continue
        for name in filenames:
            path = os.path.join(root, name)
            try:
                st = os.stat(path)
            except Exception:
                continue
            if st.st_size > max_size:
                continue
            try:
                with open(path, 'rb') as fh:
                    data = fh.read()
            except Exception:
                continue
            for match in pattern.findall(data):
                print(f"{path}:{match.decode()}")
                raise SystemExit
